Une alerte Splunk exécute une recherche périodiquement et déclenche des actions si des résultats sont trouvés :

```spl
// Requête d'alerte — brute force sur un admin
index=security EventCode=4625
| where match(Account, "(?i)admin")
| stats count AS failures BY src_ip, Account
| where failures > 20
// Déclenche si le nombre de résultats > 0

// Alerte avec score de sévérité
index=security EventCode=4625 earliest=-5m latest=now
| stats count AS failures BY src_ip
| where failures > 50
| eval severity="high"
| eval alert_message=src_ip+" : "+tostring(failures)+" failures in 5 min"
| fields src_ip, failures, severity, alert_message

// Configuration dans Splunk :
// - Fréquence : toutes les 5 minutes
// - Fenêtre : 5 minutes (earliest=-5m)
// - Condition de déclenchement : Number of results > 0
// - Actions : Email, Webhook, créer un ticket
// - Throttle : Ne pas déclencher plus d'1x par heure pour la même IP
```

```spl
// Graphe temporel — évolution des erreurs
index=security EventCode=4625 earliest=-24h
| timechart count BY host span=30m
// Utilisé dans un panel 'Line Chart'

// Camembert — distribution des EventCodes
index=security earliest=-1d
| stats count BY EventCode
| sort -count
// Utilisé dans un panel 'Pie Chart'

// Carte géographique — connexions par pays
index=web earliest=-1h
| lookup geo_lookup.csv ip AS clientip OUTPUT country, lat, lon
| stats count BY country, lat, lon
| geostats latfield=lat longfield=lon count
// Utilisé dans un panel 'Cluster Map'

// Tableau top IPs avec sparkline
index=web status>=400 earliest=-24h
| stats count AS errors sparkline BY clientip
| sort -errors
| head 20
// sparkline ajoute un mini-graphe inline

// Gauge — métrique avec seuil
index=security EventCode=4625 earliest=-1h
| stats count AS total_failures
// Utilisé dans un panel 'Gauge' avec seuils colorés
```
